    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function pickFirstString(candidates) {
  for (const candidate of candidates) {
    const text = String(candidate ?? '').trim();
    if (text) return text;
  }
  return '';
}

function resolveChunk(value) {
  if (value?.media_chunks && typeof value.media_chunks === 'object' && !Array.isArray(value.media_chunks)) {
    return value.media_chunks;
  }
  return value ?? {};
}

function chooseVoiceFileName(fileName, safeChunkKey, preferredExt) {
  const raw = safeText(fileName);
  const normalized = raw.toLowerCase();
  const hasKnownExt = /\.(wav|mp3|mpeg|ogg|m4a|flac|aac)$/i.test(raw);
  const generic = ['stream', 'audio', 'file', 'output', 'tts', 'response'].includes(normalized);

  if (!raw || generic || !hasKnownExt) {
    return 'tts-' + safeChunkKey + preferredExt;
  }

  return raw;
}

function readBinaryInfo(binaryMap) {
  const keys = Object.keys(binaryMap ?? {});
  if (keys.length === 0) {
    return {
      key: '',
      mimeType: '',
      fileName: '',
      bytes: 0,
      hasAudio: false,
      text: '',
      isBinaryReference: false,
    };
  }

  const key = keys.includes('tts_response') ? 'tts_response' : keys[0];
  const file = binaryMap[key] ?? {};
  const mimeType = safeText(file.mimeType);
  const bytes = clampInt(file.bytes, 0, 0, 1000000000);
  const contentRef = safeText(file.data);
  const isBinaryReference = contentRef === 'filesystem-v2' || contentRef.startsWith('filesystem-v2:');

  let text = '';
  if (!isBinaryReference && contentRef) {
    try {
      text = Buffer.from(contentRef, 'base64').toString('utf8');
    } catch (_) {
      text = '';
    }
  }

  return {
    key,
    mimeType,
    fileName: safeText(file.fileName),
    bytes,
    isBinaryReference,
    hasAudio: Boolean(key) && mimeType.toLowerCase().startsWith('audio/'),
    text,
  };
